#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    int *X = (int*)malloc(T*sizeof(int));
    int *Y = (int*)malloc(T*sizeof(int));
    int maxY = 0;
    for(int i=0;i<T;i++){
        scanf("%d %d", &X[i], &Y[i]);
        if(Y[i]>maxY) maxY = Y[i];
    }
    // sieve
    char *isPrime = (char*)malloc((maxY+1)*sizeof(char));
    memset(isPrime, 1, maxY+1);
    isPrime[0]=isPrime[1]=0;
    for(int p=2;p*p<=maxY;p++) if(isPrime[p]){
        for(int mult=p*p; mult<=maxY; mult+=p) isPrime[mult]=0;
    }
    for(int i=0;i<T;i++){
        int cur = X[i];
        int steps = 0;
        while(cur < Y[i]){
            if(cur+2 <= Y[i] && isPrime[cur+2]) cur += 2;
            else cur += 1;
            steps++;
        }
        printf("%d\n", steps);
    }
    free(isPrime); free(X); free(Y);
    return 0;
}

