import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        int[] X = new int[T];
        int[] Y = new int[T];
        int maxY = 0;
        for(int i=0;i<T;i++){
            X[i] = fs.nextInt();
            Y[i] = fs.nextInt();
            if(Y[i] > maxY) maxY = Y[i];
        }
        boolean[] isPrime = new boolean[maxY+1];
        Arrays.fill(isPrime, true);
        if(maxY >= 0) isPrime[0] = false;
        if(maxY >= 1) isPrime[1] = false;
        for(int p=2; p*1L*p <= maxY; p++) if(isPrime[p]){
            for(int m=p*p; m<=maxY; m+=p) isPrime[m] = false;
        }
        StringBuilder sb = new StringBuilder();
        for(int i=0;i<T;i++){
            int cur = X[i];
            int steps = 0;
            while(cur < Y[i]){
                if(cur+2 <= Y[i] && isPrime[cur+2]) cur += 2; else cur += 1;
                steps++;
            }
            sb.append(steps).append('\n');
        }
        System.out.print(sb.toString());
    }
    // fast scanner
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in){ this.in = in; }
        private int readByte() throws IOException {
            if(ptr >= len){ len = in.read(buffer); ptr = 0; if(len <= 0) return -1; }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while(c <= ' ');
            if(c=='-'){ sign = -1; c = readByte(); }
            while(c > ' '){ val = val*10 + (c - '0'); c = readByte(); }
            return val*sign;
        }
    }
}

