import sys

def sieve(limit):
    is_prime = bytearray(b'\x01') * (limit + 1)
    if limit >= 0:
        is_prime[0] = 0
    if limit >= 1:
        is_prime[1] = 0
    p = 2
    while p * p <= limit:
        if is_prime[p]:
            step = p
            start = p * p
            is_prime[start:limit+1:step] = b'\x00' * ((limit - start)//step + 1)
        p += 1
    return is_prime

def main():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    queries = []
    max_y = 0
    for _ in range(T):
        x = int(next(it)); y = int(next(it))
        queries.append((x, y))
        if y > max_y:
            max_y = y
    is_prime = sieve(max_y)
    out_lines = []
    for x, y in queries:
        cur = x
        steps = 0
        while cur < y:
            if cur + 2 <= y and is_prime[cur + 2]:
                cur += 2
            else:
                cur += 1
            steps += 1
        out_lines.append(str(steps))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

